const body = $input.first().json.body || {};
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value || {};

const messages = value.messages;
if (!Array.isArray(messages) || messages.length === 0) return [];

const msg = messages[0];
if (!msg.id || !msg.from) return [];

const phoneNumberId = value.metadata?.phone_number_id;
if (!phoneNumberId) return [];

let msg_text = '';
let is_nfm_reply = false;
let nfm_response = null;

if (msg.type === 'text') {
  msg_text = msg.text?.body || '';
} else if (msg.type === 'interactive') {
  if (msg.interactive?.type === 'nfm_reply') {
    is_nfm_reply = true;
    nfm_response = msg.interactive.nfm_reply?.response_json || '{}';
  } else if (msg.interactive?.type === 'button_reply') {
    msg_text = msg.interactive.button_reply?.id || '';
  } else if (msg.interactive?.type === 'list_reply') {
    msg_text = msg.interactive.list_reply?.id || '';
  }
}

return [{
  json: {
    message_id: msg.id,
    phone_number_id: phoneNumberId,
    customer_phone: msg.from,
    msg_type: msg.type,
    msg_text,
    is_nfm_reply,
    nfm_response,
    contact_name: value.contacts?.[0]?.profile?.name || '',
    timestamp: msg.timestamp
  }
}];

const items = $input.all();
const config = $('Config').item.json;
const filter = $('Filter & Extract').item.json;

let etapa = '';
let contexto = {};
let updated_at = null;

// Supabase REST retorna array. HTTP Request pode expandir ou nao.
let row = null;
if (items.length > 0) {
  const raw = items[0].json;
  if (Array.isArray(raw)) {
    row = raw.length > 0 ? raw[0] : null;
  } else if (raw && raw.customer_phone) {
    row = raw;
  }
}

if (row && row.customer_phone) {
  etapa = row.etapa || '';
  contexto = row.contexto || {};
  updated_at = row.updated_at;

  // Session timeout check
  if (etapa !== '' && updated_at) {
    const updatedMs = new Date(updated_at).getTime();
    const nowMs = Date.now();
    const timeoutMs = (config.session_timeout_min || 30) * 60 * 1000;
    if (nowMs - updatedMs > timeoutMs) {
      etapa = '';
      contexto = {};
    }
  }
}

// Flags para roteamento
const is_nfm_reply = filter.is_nfm_reply || false;
const msgText = (filter.msg_text || '').toLowerCase().trim();
const is_escape = ['sair', 'cancelar', '0'].includes(msgText);

return [{ json: { etapa, contexto, is_nfm_reply, is_escape } }];

const filter = $('Filter & Extract').item.json;
const state = $('Normalize State').item.json;
const config = $('Config').item.json;
const cliente = $('Busca Cliente').first().json;

let response = {};
try {
  response = JSON.parse(filter.nfm_response || '{}');
} catch (e) {
  return [{ json: { valid: false, error: 'invalid_json' } }];
}

const savedToken = state.contexto?.flow_token;
if (savedToken && response.flow_token && response.flow_token !== savedToken) {
  return [{ json: { valid: false, error: 'invalid_token' } }];
}

// Collect items with quantities from item_N_id + qty_N (v3 format)
const lines = [];
for (let i = 1; i <= 10; i++) {
  const itemId = response['item_' + i + '_id'];
  const qty = parseInt(response['qty_' + i] || '0', 10);
  if (itemId && itemId !== '' && qty > 0) {
    lines.push({ product_id: parseInt(itemId, 10), qty });
  }
}

// Build delivery address from form fields
const deliveryAddress = {};
if (response.cep) {
  deliveryAddress.new = {
    street: response.endereco || '',
    street2: response.numero || '',
    zip: response.cep || '',
    comment: [response.complemento, response.referencia].filter(Boolean).join(' - ')
  };
  deliveryAddress.add_new_address = true;
  deliveryAddress.set_as_default = false;
}

// Determine payment method
let paymentMethod = 'pix';
if (response.tipo_pagamento === 'entrega') {
  paymentMethod = response.pagamento_entrega || 'dinheiro';
} else if (response.tipo_pagamento === 'online') {
  paymentMethod = response.pagamento_online || 'pix';
}

const partnerId = cliente?.id || null;
const orderBody = {
  partner_id: partnerId,
  pos_config_id: config.pos_config_id,
  lines,
  delivery_address: deliveryAddress,
  payment_method: paymentMethod,
  notes: response.observacao || '',
  talheres: response.talheres || 'nao',
  troco_para: response.troco || null
};

return [{ json: {
  valid: true,
  order_body: orderBody,
  pagamento: {
    metodo: paymentMethod,
    troco_para: response.troco || null,
    tipo: response.tipo_pagamento || ''
  }
}}];

