const posResponse = $input.first().json;
const config = $('Config').item.json;
let canReceive = false;

// Resposta pode ser array de POS configs ou objeto unico
if (Array.isArray(posResponse)) {
  const pos = posResponse.find(p => p.id === config.pos_config_id);
  canReceive = pos ? pos.can_receive_orders !== false : false;
} else if (posResponse && typeof posResponse === 'object') {
  // Pode ser objeto com campo data ou direto
  const data = posResponse.data || posResponse;
  if (Array.isArray(data)) {
    const pos = data.find(p => p.id === config.pos_config_id);
    canReceive = pos ? pos.can_receive_orders !== false : false;
  } else {
    canReceive = data.can_receive_orders !== false;
  }
}

// return [{ json: { can_receive_orders: canReceive } }];
return [{ json: { can_receive_orders: true } }];

const config = $('Config').first().json;
const msgs = $('Messages Config').first().json;
const filter = $('Filter & Extract').first().json;
const cliente = $('Busca Cliente').first().json;

// Products from Odoo API
const productsResponse = $input.first().json;
let products = [];
if (Array.isArray(productsResponse)) {
  products = productsResponse;
} else if (productsResponse?.data && Array.isArray(productsResponse.data)) {
  products = productsResponse.data;
} else if (productsResponse?.products && Array.isArray(productsResponse.products)) {
  products = productsResponse.products;
}

// Group products by category
const catGroups = {};
for (const p of products) {
  const catId = String(p.pos_categ_id?.[0] || p.categ_id?.[0] || 'outros');
  const catName = p.pos_categ_id?.[1] || p.categ_id?.[1] || 'Outros';
  if (!catGroups[catId]) {
    catGroups[catId] = { name: catName, items: [] };
  }
  const preco = p.lst_price || p.list_price || 0;
  catGroups[catId].items.push({
    id: String(p.id),
    title: `${p.name || p.display_name} - R$${preco.toFixed(2).replace('.', ',')}`
  });
}

// Build cat_N_name, cat_N_items, cat_N_visible (max 10 slots)
const categories = Object.values(catGroups);
const initialData = {
  flow_token: '',
  has_items: false,
  has_enderecos: false,
  enderecos_salvos: [],
  metodos_pagamento: [
    { id: 'pix', title: 'PIX' },
    { id: 'cartao_entrega', title: 'Cartao na entrega' },
    { id: 'dinheiro', title: 'Dinheiro' }
  ]
};
for (let i = 1; i <= 10; i++) {
  const cat = categories[i - 1];
  initialData[`cat_${i}_name`] = cat ? cat.name : '';
  initialData[`cat_${i}_items`] = cat ? cat.items : [];
  initialData[`cat_${i}_visible`] = !!cat;
}

// Customer info
const customerName = cliente?.name || filter.contact_name || '';
const partnerId = cliente?.id || null;

// Customer delivery addresses (children contacts type=delivery)
if (cliente?.children && Array.isArray(cliente.children)) {
  const addrs = cliente.children
    .filter(c => c.type === 'delivery')
    .map(c => ({
      id: String(c.id),
      title: `${c.street || ''}, ${c.city || ''}`.replace(/^, |, $/g, '')
    }))
    .filter(a => a.title.trim());
  if (addrs.length > 0) {
    initialData.has_enderecos = true;
    initialData.enderecos_salvos = addrs;
  }
}

// Generate flow_token (anti-replay)
const flow_token = `ft_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`;
initialData.flow_token = flow_token;

// Welcome message
const isNew = !partnerId;
const msgTemplate = isNew ? msgs.msg_welcome_new : msgs.msg_welcome;
const welcomeMsg = msgTemplate.replace('{nome}', customerName).replace('{display_name}', config.display_name);

// Build complete Flow message body for Meta API
const flowMessageBody = {
  messaging_product: 'whatsapp',
  to: filter.customer_phone,
  type: 'interactive',
  interactive: {
    type: 'flow',
    body: { text: welcomeMsg },
    action: {
      name: 'flow',
      parameters: {
        flow_message_version: '3',
        flow_id: String(config.flow_id),
        flow_token,
        flow_cta: 'Abrir Cardapio',
        mode: 'draft',
        flow_action: 'navigate',
        flow_action_payload: {
          screen: 'CARDAPIO',
          data: initialData
        }
      }
    }
  }
};

// Product map for endpoint (id -> {name, price})
const productMap = {};
for (const p of products) {
  const preco = p.lst_price || p.list_price || 0;
  productMap[String(p.id)] = { name: p.name || p.display_name, price: preco };
}

return [{ json: {
  initial_data: initialData,
  flow_token,
  partner_id: partnerId,
  customer_name: customerName,
  flow_message_body: flowMessageBody,
  product_map: productMap
}}];

