const crypto = require('crypto');
const https = require('https');

const flowConfig = $('Flow Config').first().json;
const privateKeyPem = flowConfig.flow_private_key;
const supabaseUrl = flowConfig.supabase_url;
const supabaseKey = flowConfig.supabase_key;
const body = $input.first().json.body;

// --- Decrypt ---
const encryptedAesKey = Buffer.from(body.encrypted_aes_key, 'base64');
const encryptedFlowData = Buffer.from(body.encrypted_flow_data, 'base64');
const iv = Buffer.from(body.initial_vector, 'base64');

const aesKey = crypto.privateDecrypt({
  key: privateKeyPem,
  padding: crypto.constants.RSA_PKCS1_OAEP_PADDING,
  oaepHash: 'sha256',
}, encryptedAesKey);

const TAG_LENGTH = 16;
const ct = encryptedFlowData.slice(0, -TAG_LENGTH);
const authTag = encryptedFlowData.slice(-TAG_LENGTH);
const decipher = crypto.createDecipheriv('aes-128-gcm', aesKey, iv);
decipher.setAuthTag(authTag);
const decrypted = Buffer.concat([decipher.update(ct), decipher.final()]);
const request = JSON.parse(decrypted.toString('utf8'));

// --- Helper: encrypt response ---
function encryptResponse(responseObj) {
  const str = JSON.stringify(responseObj);
  const newIv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-128-gcm', aesKey, newIv);
  const enc = Buffer.concat([cipher.update(str, 'utf8'), cipher.final(), cipher.getAuthTag()]);
  return { encrypted_flow_data: enc.toString('base64'), initial_vector: newIv.toString('base64') };
}

// --- Helper: HTTPS GET ---
function httpGet(url, headers) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const opts = { hostname: u.hostname, path: u.pathname + u.search, headers, method: 'GET' };
    const req = https.request(opts, (res) => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve(d); } });
    });
    req.on('error', reject);
    req.end();
  });
}

// --- Handle action ---
let result;

if (request.action === 'ping' || request.action === 'INIT') {
  result = encryptResponse({ version: '3.0', data: { status: 'active' } });

} else if (request.action === 'data_exchange') {
  const formData = request.data || {};
  const flowToken = formData.flow_token || '';

  // Collect selected item IDs from cat_1..cat_10
  const selectedIds = [];
  for (let i = 1; i <= 10; i++) {
    const items = formData['cat_' + i];
    if (Array.isArray(items)) selectedIds.push(...items);
  }

  // Fetch product_map from Supabase (stored in flow_conversations.contexto)
  const filterUrl = supabaseUrl + '/rest/v1/flow_conversations?select=contexto&contexto-%3E%3Eflow_token=eq.' + encodeURIComponent(flowToken) + '&limit=1';
  const rows = await httpGet(filterUrl, {
    apikey: supabaseKey,
    Authorization: 'Bearer ' + supabaseKey
  });
  const productMap = (Array.isArray(rows) && rows[0] && rows[0].contexto && rows[0].contexto.product_map) || {};

  // Build CARRINHO screen data
  const carrinhoData = {
    flow_token: flowToken,
    qty_options: Array.from({length: 10}, (_, i) => ({ id: String(i+1), title: String(i+1) }))
  };
  for (let i = 1; i <= 10; i++) {
    const itemId = selectedIds[i - 1];
    if (itemId) {
      const prod = productMap[itemId] || {};
      const name = prod.name || 'Item ' + itemId;
      const price = prod.price || 0;
      carrinhoData['item_' + i + '_id'] = itemId;
      carrinhoData['item_' + i + '_name'] = name + ' - R$' + price.toFixed(2).replace('.', ',');
      carrinhoData['item_' + i + '_visible'] = true;
    } else {
      carrinhoData['item_' + i + '_id'] = '';
      carrinhoData['item_' + i + '_name'] = '';
      carrinhoData['item_' + i + '_visible'] = false;
    }
  }

  result = encryptResponse({ version: '3.0', screen: 'CARRINHO', data: carrinhoData });

} else {
  result = encryptResponse({ version: '3.0', data: { status: 'active' } });
}

return [{ json: result }];
